VALUES
  ('retired-d0d1b9a2-moex-00050', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，甲機關委託乙財團法人辦理 A 計畫，依契約規 定支付委辦費12萬元，並認列為業務支出，但截至年度終了尚有4萬元未辦理完成，甲機關應 將業務支出調整轉列為下列何項科目及金額？', '["暫付款4萬元", "暫收款8萬元", "預付款4萬元", "預收款8萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "00cd0a7e977c", "answer_pdf_sha1": "7bbbd5c2f8ba", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00051', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '甲機關某日交易明細如下：①取得於金融機構所設之接受民眾捐款帳戶，指定用於賑災之捐款300', '["Y工程得標廠商繳交之履約保證金100萬元", "K社區發展協會退還當年度補助款150 萬元", "M公司繳納之許可證照規費10萬元。依中央政府普通公務單位會計制度之一致規定， 上述交易不會影響甲機關的那一個會計科目？", "應付代收款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "00cd0a7e977c", "answer_pdf_sha1": "7bbbd5c2f8ba", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00052', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '甲機關辦理工程招標時，允許投標廠商以現金、票據、有價證券等作為押標金，開標後退還未得 標廠商。依中央政府普通公務單位會計制度之一致規定，下列甲機關針對上述交易之處理，何者 正確？', '["收到押標金時，一律認列為信託代理及保證資產／負債項下各該科目，並列示於平衡表資產負 債項下", "收到現金押標金時，應貸記應付保管款，列示於平衡表負債項下。收到非現金押標金時，則認 列為信託代理及保證資產／負債項下各該科目，並列示於平衡表資產負債項下", "收到現金押標金時，貸記存入保證金，列示於平衡表負債項下。收到非現金押標金時，則認列 為信託代理及保證資產／負債項下各該科目，以附註表達", "收到現金押標金時，貸記暫收款，列示於平衡表資產項下。收到非現金押標金時，則認列為信 託代理及保證資產／負債項下各該科目，以附註表達"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "00cd0a7e977c", "answer_pdf_sha1": "7bbbd5c2f8ba", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00053', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '中央政府甲機關X1年度由公庫撥款支付廠商款項550萬元，同年12月31日查明尚應付廠商款 項50萬元；另收回以前年度已認列獎補助支出之賸餘款50萬元，和以前年度支付之存出保證金 100萬元，均辦理繳庫，依中央政府普通公務單位會計制度之一致規定，計算公庫撥入數科目之 金額為下列何者？', '["500萬元", "550萬元", "600萬元", "700萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "00cd0a7e977c", "answer_pdf_sha1": "7bbbd5c2f8ba", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
