  ('retired-d0d1b9a2-moex-00059', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依國立大學校院校務基金會計制度之一致規定，國立大學以政府機關（構）獎補助款項購置資產， 於資產提列折舊時，下列分錄何者正確？', '["借：折舊費用，貸，累計折舊－不動產、廠房及設備", "借：折舊費用，貸：累計折舊－不動產、廠房及設備；借：遞延收入，貸：其他補助收入", "借：折舊費用，貸：累計折舊－不動產、廠房及設備；借：預收收入，貸：其他補助收入", "借：折舊費用，貸：累計折舊－不動產、廠房及設備；借：遞延收入，貸：其他收入"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "00cd0a7e977c", "answer_pdf_sha1": "7bbbd5c2f8ba", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
